    const items = await listNotifications(userId, { channel: "whatsapp", limit: 10 });
    assert.equal(items.length, 1);
    assert.equal(items[0]?.delivered, true);
    assert.equal(items[0]?.error, null);
  } finally {
    global.fetch = originalFetch;
  }
});

